#include <iostream>
#include <string>

class IntStack {
    int* data;
    int size_;
    int cap_;
public:
    explicit IntStack(int cap)
        : data{new int[static_cast<std::size_t>(cap)]}, size_{0}, cap_{cap}
    {}
    ~IntStack() { delete[] data; }
    void push(int v) { data[size_++] = v; }
    void pop()       { --size_; }
    int top() const  { return data[size_ - 1]; }
    int size() const { return size_; }
};

int main() {
    int cap{}, n{};
    std::cin >> cap >> n;
    IntStack s{cap};
