#include <iostream>
#include <string>

class FixedQueue {
    int data[8]{};
    int head_{0};
    int tail_{0};
    int count_{0};
    int cap_;
public:
    explicit FixedQueue(int cap) : cap_{cap} {}
    void enqueue(int v) {
        data[tail_] = v;
        tail_ = (tail_ + 1) % cap_;
        ++count_;
    }
    int dequeue() {
        int v = data[head_];
        head_ = (head_ + 1) % cap_;
        --count_;
        return v;
    }
    int count() const { return count_; }
};

int main() {
    int cap{}, n{};
    std::cin >> cap >> n;
    FixedQueue q{cap};
    for (int i = 0; i < n; ++i) {
        std::string op;
        std::cin >> op;
        if (op == "enqueue") {
            int v{};
            std::cin >> v;
            q.enqueue(v);
        } else if (op == "dequeue") {
            std::cout << q.dequeue() << "\n";
        } else if (op == "count") {
            std::cout << q.count() << "\n";
        }
    }
    return 0;
}
